import random
import os
from typing import Callable

class INDCPAGame:
    def __init__(self, encrypt_fn: Callable, key_gen_fn: Callable):
        self.encrypt = encrypt_fn
        self.key_gen = key_gen_fn
        self.key = None
        self.challenge_bit = None

    def setup(self):
        self.key = self.key_gen()
        self.challenge_bit = random.randint(0, 1)

    def challenge(self, m0: bytes, m1: bytes) -> bytes:
        assert len(m0) == len(m1), "Messages must be equal length"
        chosen_message = m0 if self.challenge_bit == 0 else m1
        return self.encrypt(self.key, chosen_message)

    def guess(self, b_guess: int) -> bool:
        return b_guess == self.challenge_bit

def run_ind_cpa_experiment(game: INDCPAGame, adversary: Callable, trials: int = 1000) -> float:
    wins = 0
    for _ in range(trials):
        game.setup()
        guess = adversary(game)
        if game.guess(guess):
            wins += 1
    advantage = abs(wins / trials - 0.5)
    return advantage

def classical_security_bits(algorithm: str, key_size: int) -> int:
    algorithm = algorithm.upper()
    if algorithm == 'AES':
        return key_size  # AES-128 = 128 bits, etc.
    elif algorithm == 'RSA':
        # Approximate RSA security
        if key_size <= 1024:
            return 80
        elif key_size <= 2048:
            return 112
        elif key_size <= 3072:
            return 128
        else:
            return 140
    elif algorithm == 'ECC':
        return key_size // 2  # ECC-256 = 128 bits
    return 0

def quantum_security_bits(algorithm: str, key_size: int) -> int:
    algorithm = algorithm.upper()
    if algorithm == 'AES':
        # Grover's algorithm halves security
        return key_size // 2
    elif algorithm in ['RSA', 'ECC']:
        # Shor's algorithm breaks these completely
        return 0
    return 0

def nist_security_level(quantum_bits: int) -> int:
    if quantum_bits >= 256:
        return 5
    elif quantum_bits >= 128:
        return 3
    elif quantum_bits >= 64:
        return 1
    else:
        return 0  # Not secure

def analyze_algorithm(algorithm: str, key_size: int) -> dict:
    classical = classical_security_bits(algorithm, key_size)
    quantum = quantum_security_bits(algorithm, key_size)
    level = nist_security_level(quantum)

    return {
        'algorithm': algorithm,
        'key_size': key_size,
        'classical_bits': classical,
        'quantum_bits': quantum,
        'nist_level': level,
        'quantum_safe': quantum >= 64
    }

import os
from collections import Counter

def otp_encrypt(plaintext: bytes, key: bytes) -> bytes:
    assert len(key) >= len(plaintext), "Key must be at least as long as plaintext"
    return bytes(p ^ k for p, k in zip(plaintext, key))

def otp_decrypt(ciphertext: bytes, key: bytes) -> bytes:
    return bytes(c ^ k for c, k in zip(ciphertext, key))

def find_key_for_message(ciphertext: bytes, target_plaintext: bytes) -> bytes:
    # Key = ciphertext XOR target_plaintext
    # This key will decrypt ciphertext to target_plaintext
    return bytes(c ^ p for c, p in zip(ciphertext, target_plaintext))

def demonstrate_perfect_secrecy():
    # Original encryption
    original = b"ATTACK"
    key = os.urandom(len(original))
    ciphertext = otp_encrypt(original, key)

    # Show same ciphertext can be any message
    messages = [b"ATTACK", b"DEFEND", b"IGNORE", b"SUBMIT"]
    results = []

    for msg in messages:
        k = find_key_for_message(ciphertext, msg)
        decrypted = otp_decrypt(ciphertext, k)
        results.append({
            'key': k.hex(),
            'plaintext': decrypted.decode('ascii', errors='replace')
        })

    return {
        'ciphertext': ciphertext.hex(),
        'possible_decryptions': results,
        'conclusion': 'Any plaintext is equally valid!'
    }
